DECLARE @E_DW_CNT VARCHAR(10) = (SELECT CODE_VAL FROM SYS_CODE WHERE CODE_GROUP_CD = 'SYS_EMAIL_FILE' AND CODE_CD = 'EMAIL_DW_CNT');
SELECT EMAIL_FILE_SEQ , FILE_NM , '링크복사' AS filecopy , '/common/fileDownload?fileId=' + FILE_G.FILE_GRP_ID AS fileLink , (SELECT CODE_VAL FROM SYS_CODE WHERE CODE_GROUP_CD = 'SYS_EMAIL_STATUS' AND CODE_CD = IIF(STATUS = 'FILE_DEL', 'FILE_DEL', IIF(DOWN_CNT >= @E_DW_CNT, 'DW_N', IIF(GETDATE() >= DEL_DT, 'DW_N', IIF(STATUS = 'DW_Y', STATUS, 'DW_N')))) ) AS STATUS , dbo.getUserNm(FILE_E.REG_USER_SEQ) AS REG_USER_NM , CONVERT(VARCHAR,DOWN_CNT)+' / '+@E_DW_CNT MAX_DOWN_CNT , FILE_G.FILE_GRP_ID , FILE_G.FILE_GRP_SEQ , CONVERT(VARCHAR(19), FILE_E.REG_DT, 120) REG_DT , CONVERT(VARCHAR(19), DEL_DT, 120) DEL_DT , RMK
FROM SYS_EMAIL_FILE AS FILE_E LEFT JOIN SYS_FILE_GROUP AS FILE_G ON FILE_E.FILE_GRP_SEQ = FILE_G.FILE_GRP_SEQ LEFT JOIN (SELECT FILE_GRP_SEQ, MAX(DOWN_CNT) AS DOWN_CNT, MAX( CASE WHEN RN = 1 THEN FILE_NM + CASE WHEN CNT > 1 THEN ' 외 ' + CAST(CNT - 1 AS VARCHAR) + '건' ELSE '' END END ) AS FILE_NM FROM ( SELECT F.FILE_GRP_SEQ ,F.FILE_NM ,F.DOWN_CNT ,F.SORT ,ROW_NUMBER() OVER (PARTITION BY F.FILE_GRP_SEQ ORDER BY F.SORT) AS RN ,COUNT(1) OVER (PARTITION BY F.FILE_GRP_SEQ) AS CNT FROM SYS_FILE F WHERE F.FILE_GRP_SEQ IN ( SELECT FILE_GRP_SEQ FROM SYS_EMAIL_FILE WHERE 1 = 1 ) ) T GROUP BY FILE_GRP_SEQ) GRP_FILE ON FILE_E.FILE_GRP_SEQ = GRP_FILE.FILE_GRP_SEQ WHERE 1 = 1 AND ((SELECT USER_SEQ FROM SYS_USER WHERE USER_ID = 'OP_ADMIN') = #{loginUserSeq} or FILE_E.REG_USER_SEQ = #{loginUserSeq}) ORDER BY REG_DT DESC

